command:
$ErrorActionPreference = 'Stop'
Set-StrictMode -Version 2.0
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { $repo = $env:GITHUB_WORKSPACE }
if ([string]::IsNullOrWhiteSpace($repo) -or -not (Test-Path -LiteralPath $repo -PathType Container)) { throw 'Unable to resolve repository root.' }
$branch = 'codex/issue-267-powershell-engine-pester-boundary'
$expectedHead = 'c2b9aa5925f9eb363ff9b24cac955368d9b9404b'
$requestId = 'exec-20260615-pr271-line-count-path-policy-012'
$fetchRefspec = "+refs/heads/${branch}:refs/remotes/origin/${branch}"
$pushRefspec = "HEAD:refs/heads/${branch}"
$tempRoot = $env:RUNNER_TEMP
if ([string]::IsNullOrWhiteSpace($tempRoot)) { $tempRoot = [IO.Path]::GetTempPath() }
$worktree = Join-Path $tempRoot $requestId
$patchScript = Join-Path $tempRoot "$requestId.py"
$expectedBlobs = @{
    'project_sources/collector/tools/build_powershell_surface_inventory.py' = '7530fbd6d87c07955e761bd3142b5855096a48a8'
    'project_sources/collector/tools/run_powershell_assembly_parity.py' = '97060f177136bb48ec0f14cdf1f316fa43a2bd55'
}
$expectedPaths = @('project_sources/collector/tools/build_powershell_surface_inventory.py', 'project_sources/collector/tools/run_powershell_assembly_parity.py')
$validationResults = New-Object System.Collections.Generic.List[string]
function Invoke-Git {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string[]]$GitArgs)
    $old = $ErrorActionPreference; $output = @(); $exitCode = $null
    try { $ErrorActionPreference = 'Continue'; $output = & git -C $Cwd @GitArgs 2>&1; $exitCode = $LASTEXITCODE } finally { $ErrorActionPreference = $old }
    if ($exitCode -ne 0) { throw "git $($GitArgs -join ' ') failed with exit code $exitCode`n$output" }
    return $output
}
function Invoke-NativeCommand {
    param([Parameter(Mandatory=$true)][string]$FilePath, [Parameter(Mandatory=$true)][string[]]$Arguments, [Parameter(Mandatory=$true)][string]$Description)
    $old = $ErrorActionPreference; $output = @(); $exitCode = $null
    try { $ErrorActionPreference = 'Continue'; $output = & $FilePath @Arguments 2>&1; $exitCode = $LASTEXITCODE } finally { $ErrorActionPreference = $old }
    if ($exitCode -ne 0) { throw "$Description failed with exit code $exitCode`n$output" }
    return $output
}
function Get-GitText { param([string]$Cwd, [string[]]$GitArgs) return ((Invoke-Git -Cwd $Cwd -GitArgs $GitArgs | Out-String).Trim()) }
function Get-TrackedBlob {
    param([string]$Cwd, [string]$Path)
    $line = Get-GitText -Cwd $Cwd -GitArgs @('ls-files','-s','--',$Path)
    if ([string]::IsNullOrWhiteSpace($line)) { return '' }
    return (($line -split '\s+')[1])
}
function Get-RequiredGitToken {
    foreach ($name in @('DCOIR_GITHUB_FG_TOKEN','DCOIR_GITHUB_CL_TOKEN')) {
        $value = [Environment]::GetEnvironmentVariable($name, 'Process')
        if ([string]::IsNullOrWhiteSpace($value)) { $value = [Environment]::GetEnvironmentVariable($name, 'Machine') }
        if (-not [string]::IsNullOrWhiteSpace($value)) { Write-Host "Using bridged GitHub token secret for PR branch push: $name"; Write-Host "::add-mask::$value"; return $value }
    }
    throw 'No bridged GitHub token secret is available for PR branch push.'
}
function Invoke-GitPushWithToken {
    param([string]$Cwd, [string]$Token, [string]$Refspec)
    $repoFull = $env:GITHUB_REPOSITORY
    if ([string]::IsNullOrWhiteSpace($repoFull)) { $repoFull = 'DCOIR-Collector/dcoir-collector' }
    $pushUrl = "https://x-access-token:${Token}@github.com/${repoFull}.git"
    $old = $ErrorActionPreference; $output = @(); $exitCode = $null
    try { $ErrorActionPreference = 'Continue'; $output = & git -C $Cwd -c 'http.https://github.com/.extraheader=' push $pushUrl $Refspec 2>&1; $exitCode = $LASTEXITCODE } finally { $ErrorActionPreference = $old }
    if ($exitCode -ne 0) { $safeOutput = (($output | Out-String).Replace($Token, '[REDACTED:GITHUB_TOKEN]')).Trim(); throw "git push failed with exit code $exitCode`n$safeOutput" }
    return $output
}
Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec) | Out-Null
$remoteHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
if ($remoteHead -ne $expectedHead) { throw "PR branch head mismatch. Expected $expectedHead but origin/$branch is $remoteHead." }
if (Test-Path -LiteralPath $worktree) { Remove-Item -LiteralPath $worktree -Recurse -Force }
Invoke-Git -Cwd $repo -GitArgs @('worktree','prune') | Out-Null
Invoke-Git -Cwd $repo -GitArgs @('worktree','add','--detach',$worktree,"origin/$branch") | Out-Null
try {
    foreach ($path in $expectedPaths) {
        $actualBlob = Get-TrackedBlob -Cwd $worktree -Path $path
        if ($actualBlob -ne $expectedBlobs[$path]) { throw "Blob mismatch before patch for $path. Expected $($expectedBlobs[$path]) but got $actualBlob." }
    }
    $pythonPatch = @'
from pathlib import Path
import sys

repo = Path(sys.argv[1])
paths = [
    repo / "project_sources/collector/tools/build_powershell_surface_inventory.py",
    repo / "project_sources/collector/tools/run_powershell_assembly_parity.py",
]
old = 'b"\\\\n"'
new = 'b"\\n"'
for path in paths:
    text = path.read_text(encoding="utf-8")
    occurrences = text.count(old)
    if occurrences != 2:
        raise SystemExit(f"Expected exactly two escaped-newline byte literals in {path}, found {occurrences}")
    text = text.replace(old, new)
    if old in text:
        raise SystemExit(f"Escaped-newline byte literal remains in {path}")
    if 'count(b"\\n")' not in text or 'endswith(b"\\n")' not in text:
        raise SystemExit(f"Expected newline-count literals missing after patch in {path}")
    path.write_text(text, encoding="utf-8", newline="\n")
'@
    [System.IO.File]::WriteAllText($patchScript, $pythonPatch, (New-Object System.Text.UTF8Encoding($false)))
    Invoke-NativeCommand -FilePath 'python' -Arguments @($patchScript, $worktree) -Description 'Patch script' | Out-Null
    $validationResults.Add('patch_script: pass') | Out-Null
    Invoke-NativeCommand -FilePath 'python' -Arguments @('-m','py_compile', (Join-Path $worktree 'project_sources/collector/tools/build_powershell_surface_inventory.py'), (Join-Path $worktree 'project_sources/collector/tools/run_powershell_assembly_parity.py')) -Description 'py_compile focused files' | Out-Null
    $validationResults.Add('py_compile_focused: pass') | Out-Null
    Invoke-NativeCommand -FilePath 'python' -Arguments @((Join-Path $worktree 'project_sources/collector/tools/test_build_powershell_surface_inventory_path_safety.py')) -Description 'inventory path-safety tests' | Out-Null
    $validationResults.Add('inventory_path_safety_tests: pass') | Out-Null
    Invoke-NativeCommand -FilePath 'python' -Arguments @((Join-Path $worktree 'project_sources/collector/tools/test_run_powershell_assembly_parity.py')) -Description 'assembly parity tests' | Out-Null
    $validationResults.Add('assembly_parity_tests: pass') | Out-Null
    Invoke-NativeCommand -FilePath 'python' -Arguments @((Join-Path $worktree 'project_sources/collector/tools/test_run_powershell_custom_checks.py')) -Description 'custom check tests' | Out-Null
    $validationResults.Add('custom_check_tests: pass') | Out-Null
    Invoke-NativeCommand -FilePath 'python' -Arguments @('-m','unittest','discover','-s',(Join-Path $worktree 'project_sources/collector/tools'),'-p','test_*.py') -Description 'collector tools unittest discovery' | Out-Null
    $validationResults.Add('collector_tools_unittest_discovery: pass') | Out-Null
    Invoke-Git -Cwd $worktree -GitArgs @('diff','--check','--') | Out-Null
    $validationResults.Add('git_diff_check: pass') | Out-Null
    Invoke-Git -Cwd $worktree -GitArgs @('config','user.name','github-actions[bot]') | Out-Null
    Invoke-Git -Cwd $worktree -GitArgs @('config','user.email','41898282+github-actions[bot]@users.noreply.github.com') | Out-Null
    Invoke-Git -Cwd $worktree -GitArgs (@('add','--') + $expectedPaths) | Out-Null
    Invoke-Git -Cwd $worktree -GitArgs @('diff','--cached','--check') | Out-Null
    $validationResults.Add('git_diff_cached_check: pass') | Out-Null
    $changedNames = Get-GitText -Cwd $worktree -GitArgs @('diff','--cached','--name-only')
    $actualPaths = @($changedNames -split "`r?`n" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    $unexpected = @($actualPaths | Where-Object { $expectedPaths -notcontains $_ })
    $missing = @($expectedPaths | Where-Object { $actualPaths -notcontains $_ })
    if ($unexpected.Count -ne 0 -or $missing.Count -ne 0) { throw "Cached diff paths mismatch. Actual paths:`n$changedNames" }
    Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec) | Out-Null
    $prePushHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
    if ($prePushHead -ne $expectedHead) { throw "PR branch moved before push. Expected $expectedHead but origin/$branch is $prePushHead." }
    $commitParent = Get-GitText -Cwd $worktree -GitArgs @('rev-parse','HEAD')
    Invoke-Git -Cwd $worktree -GitArgs @('commit','-m','Restore PowerShell file fact newline counts','-m','Correct the discovery-root path-policy follow-up so file fact line_count uses newline byte literals rather than literal backslash-n bytes.') | Out-Null
    $newHead = Get-GitText -Cwd $worktree -GitArgs @('rev-parse','HEAD')
    $token = Get-RequiredGitToken
    Invoke-GitPushWithToken -Cwd $worktree -Token $token -Refspec $pushRefspec | Out-Null
    Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec) | Out-Null
    $remoteReadbackHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
    if ($remoteReadbackHead -ne $newHead) { throw "Push readback mismatch. New commit $newHead but origin/$branch reads $remoteReadbackHead." }
    Write-Host "DCOIR_EXEC_RESULT: success"
    Write-Host "DCOIR_EXEC_REQUEST_ID: $requestId"
    Write-Host "DCOIR_EXEC_BRANCH: $branch"
    Write-Host "DCOIR_EXEC_PARENT: $commitParent"
    Write-Host "DCOIR_EXEC_NEW_HEAD: $newHead"
    Write-Host "DCOIR_EXEC_CHANGED_PATHS: $($actualPaths -join ',')"
    Write-Host "DCOIR_EXEC_VALIDATION: $($validationResults -join '; ')"
}
finally {
    try { if (Test-Path -LiteralPath $worktree) { Invoke-Git -Cwd $repo -GitArgs @('worktree','remove','--force',$worktree) | Out-Null } } catch { Write-Warning "Temporary worktree cleanup failed: $($_.Exception.Message)" }
}
